import React, { useMemo, useState } from 'react';
import {
  Area,
  AreaChart,
  Brush,
  CartesianGrid,
  Legend,
  Line,
  ReferenceDot,
  ReferenceLine,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import { formatCurrency } from '../../utils/format';
import { formatChartAxis } from '../../utils/costCurrency';

function CostTooltip({ active, payload, label, currency }) {
  if (!active || !payload?.length) return null;
  const costRow = payload.find((p) => p.dataKey === 'cost');
  const forecastRow = payload.find((p) => p.dataKey === 'forecast');
  return (
    <div className="chart-tooltip">
      <div className="chart-tooltip__date">{label}</div>
      {costRow && (
        <div className="chart-tooltip__value">
          {formatCurrency(costRow.value, { currency, decimals: 0 })}
        </div>
      )}
      {forecastRow?.value != null && (
        <div className="chart-tooltip__forecast">
          Forecast: {formatCurrency(forecastRow.value, { currency, decimals: 0 })}
        </div>
      )}
    </div>
  );
}

export default function DashboardDailyCostChart({
  chartData,
  anomalies,
  budgetLine,
  currency,
  chartCurrency,
}) {
  const [hiddenSeries, setHiddenSeries] = useState({});
  const [brushRange, setBrushRange] = useState(null);
  const visibleChartData = useMemo(() => {
    if (!brushRange) return chartData;
    const [start, end] = brushRange;
    return chartData.slice(start, end + 1);
  }, [chartData, brushRange]);

  if (!chartData?.length) return null;

  return (
    <div className="chart-slot">
      <div className="cost-trend-chart__toolbar">
        <div className="cost-trend-chart__legend-toggles" role="group" aria-label="Chart series">
          <button
            type="button"
            className={`cost-trend-chart__legend-btn${hiddenSeries.spend ? '' : ' cost-trend-chart__legend-btn--active'}`}
            onClick={() => setHiddenSeries((prev) => ({ ...prev, spend: !prev.spend }))}
          >
            Spend
          </button>
          <button
            type="button"
            className={`cost-trend-chart__legend-btn${hiddenSeries.forecast ? '' : ' cost-trend-chart__legend-btn--active'}`}
            onClick={() => setHiddenSeries((prev) => ({ ...prev, forecast: !prev.forecast }))}
          >
            Forecast
          </button>
        </div>
        {brushRange && (
          <button type="button" className="btn btn-ghost btn-sm" onClick={() => setBrushRange(null)}>
            Reset zoom
          </button>
        )}
      </div>
      <ResponsiveContainer width="100%" height={220}>
        <AreaChart data={visibleChartData}>
          <defs>
            <linearGradient id="costGradient" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="var(--primary)" stopOpacity={0.15} />
              <stop offset="95%" stopColor="var(--primary)" stopOpacity={0} />
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
          <XAxis dataKey="date" tick={{ fill: 'var(--text3)', fontSize: 10 }} />
          <YAxis tick={{ fill: 'var(--text3)', fontSize: 10 }} tickFormatter={(v) => formatChartAxis(v, currency)} />
          <Tooltip content={<CostTooltip currency={chartCurrency} />} />
          <Legend />
          {!hiddenSeries.spend && (
            <Area
              type="monotone"
              dataKey="cost"
              name="Spend"
              stroke="var(--primary)"
              strokeWidth={2}
              fill="url(#costGradient)"
              dot={false}
            />
          )}
          {!hiddenSeries.forecast && (
            <Line
              type="monotone"
              dataKey="forecast"
              name="Forecast"
              stroke="var(--warning)"
              strokeWidth={1.5}
              strokeDasharray="4 4"
              dot={false}
              connectNulls
            />
          )}
          {budgetLine != null && (
            <ReferenceLine
              y={budgetLine / 30}
              stroke="var(--danger)"
              strokeDasharray="6 4"
              label={{ value: 'Budget', fill: 'var(--danger)', fontSize: 10 }}
            />
          )}
          {anomalies.map((d) => (
            <ReferenceDot
              key={d.date}
              x={d.date}
              y={d.cost}
              r={4}
              fill="var(--danger)"
              stroke="none"
            />
          ))}
          <Brush
            dataKey="date"
            height={22}
            stroke="var(--border)"
            onChange={(range) => {
              if (range?.startIndex != null && range?.endIndex != null) {
                setBrushRange([range.startIndex, range.endIndex]);
              }
            }}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}
